{"npsn":"40202011","name":"SMP MUHAMMADIYAH LAKEA","address":"Jl. Trans Sulawesi","village":"Ilambe","status":"Swasta","jenjang":"SMP","district":"Lakea","regencyBpsCode":"7205","regencyName":"Kabupaten Buol","provinceName":"Sulawesi Tengah","school_id":"2d6f2c46-1e8d-4eb5-8311-db3d92c8faac","user_id":"8a11c845-2a57-47e8-ae57-0602f41dd4ea","password_hash":"$2b$04$rFfGfqBvEag6BnEdQyBnru4eOBdbAfs75K2DCpLcH8yLbQZtW0EcW"},
